export const 伐惡符六 = (bi) => {
    const u = bi.u, k = 1.6;
    const X = (c) => (c - 4.0) * k;
    const Z = (r) => (r - 4.6) * k + 1.0;
    const 線 = (書, 寬 = 0.6) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // 頂桁右折垂壁
    出(p => p.M(X(0.63), Z(4.95))
        .C(X(2.5), Z(4.85), X(5.5), Z(4.95), X(6.85), Z(4.88))
        .C(X(7.15), Z(4.95), X(7.25), Z(5.15), X(7.22), Z(5.4))
        .L(X(7.15), Z(13.2))
        .C(X(7.12), Z(13.35), X(7.05), Z(13.45), X(6.95), Z(13.52)), 0.64);
    // 左開桁疊三
    出(p => p.M(X(0.63), Z(6.0)).C(X(2.0), Z(5.9), X(3.6), Z(5.98), X(4.75), Z(5.9)), 0.6);
    出(p => p.M(X(0.62), Z(7.3)).C(X(2.2), Z(7.2), X(4.3), Z(7.28), X(5.75), Z(7.2)), 0.6);
    出(p => p.M(X(0.63), Z(8.6)).C(X(2.2), Z(8.5), X(4.4), Z(8.58), X(5.88), Z(8.5)), 0.6);
    // 攢角口框
    出(p => p.M(X(2.0), Z(10.6))
        .C(X(2.3), Z(10.6), X(5.5), Z(10.56), X(6.62), Z(10.56)), 0.56);
    出(p => p.M(X(2.16), Z(10.54)).L(X(2.1), Z(12.66)), 0.54);
    出(p => p.M(X(6.5), Z(10.6)).L(X(6.54), Z(12.58)), 0.54);
    出(p => p.M(X(2.0), Z(12.72))
        .C(X(2.3), Z(12.6), X(5.5), Z(12.64), X(6.64), Z(12.52)), 0.56);
    // 桁疊四
    出(p => p.M(X(0.63), Z(14.05)).C(X(2.2), Z(13.95), X(4.4), Z(14.03), X(6.13), Z(13.95)), 0.6);
    出(p => p.M(X(0.62), Z(15.25)).C(X(2.2), Z(15.15), X(4.4), Z(15.23), X(6.13), Z(15.15)), 0.6);
    出(p => p.M(X(0.63), Z(16.45)).C(X(2.2), Z(16.35), X(4.4), Z(16.43), X(6.13), Z(16.35)), 0.6);
    出(p => p.M(X(0.62), Z(17.55)).C(X(2.2), Z(17.45), X(4.4), Z(17.53), X(6.13), Z(17.45)), 0.6);
    // 雙皿彎
    出(p => p.M(X(1.5), Z(19.1))
        .C(X(1.6), Z(19.42), X(2.6), Z(19.52), X(3.9), Z(19.48))
        .C(X(4.9), Z(19.45), X(5.7), Z(19.3), X(5.88), Z(19.05)), 0.58);
    出(p => p.M(X(1.62), Z(20.55))
        .C(X(1.72), Z(20.87), X(2.7), Z(20.97), X(3.95), Z(20.93))
        .C(X(4.9), Z(20.9), X(5.6), Z(20.62), X(5.78), Z(20.5)), 0.58);
    // 桁疊三
    出(p => p.M(X(0.63), Z(21.95)).C(X(2.2), Z(21.85), X(4.4), Z(21.93), X(6.13), Z(21.85)), 0.6);
    出(p => p.M(X(0.62), Z(23.15)).C(X(2.2), Z(23.05), X(4.4), Z(23.13), X(6.13), Z(23.05)), 0.6);
    出(p => p.M(X(0.63), Z(24.3)).C(X(2.2), Z(24.2), X(4.4), Z(24.28), X(6.13), Z(24.2)), 0.6);
    // 摺帶三程
    出(p => p.M(X(0.62), Z(25.65))
        .C(X(2.2), Z(25.55), X(4.5), Z(25.63), X(5.75), Z(25.56))
        .C(X(6.2), Z(25.68), X(6.2), Z(26.25), X(5.75), Z(26.37))
        .C(X(4.4), Z(26.47), X(2.4), Z(26.4), X(1.1), Z(26.48))
        .C(X(0.56), Z(26.6), X(0.56), Z(27.15), X(1.1), Z(27.27))
        .C(X(2.5), Z(27.37), X(4.5), Z(27.3), X(5.88), Z(27.38)), 0.62);
    // 大∪彎
    出(p => p.M(X(1.5), Z(29.3))
        .C(X(1.45), Z(30.6), X(2.2), Z(31.4), X(3.75), Z(31.45))
        .C(X(5.3), Z(31.5), X(6.05), Z(30.58), X(6.0), Z(29.45)), 0.62);
    // 底波桁
    出(p => p.M(X(0.62), Z(32.6))
        .C(X(1.6), Z(32.45), X(3.2), Z(32.55), X(4.4), Z(32.5))
        .C(X(5.1), Z(32.47), X(5.6), Z(32.55), X(5.75), Z(32.75)), 0.62);
};
